import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, loading } = useAuth();

  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(true);

  const [darkMode] = useState(
    localStorage.getItem("user-theme") === "dark"
  );

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setTitle(res.data.title);
        setBody(res.data.body);
        setPreview(
          res.data.image
            ? `http://localhost:5000/uploads/${res.data.image}`
            : ""
        );
      } catch (err) {
        setError("Failed to load post.");
      } finally {
        setFetching(false);
      }
    };

    fetchPost();
  }, [id]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("body", body);
      if (image) formData.append("image", image);

      await API.put(`/posts/${id}`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      navigate(`/posts/${id}`);
    } catch (err) {
      setError("Failed to update post.");
    } finally {
      setSaving(false);
    }
  };

  if (loading || fetching) {
    return <div style={styles.loading}>Loading...</div>;
  }

  if (!user) {
    return <div style={styles.error}>Unauthorized access.</div>;
  }

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <h2 style={styles.title}>✏️ Edit Post</h2>

        {error && <div style={styles.errorBox}>{error}</div>}

        {/* 🔥 FIX: FORM LAYOUT CONTROL (IMPORTANT) */}
        <form onSubmit={handleUpdate} style={styles.form}>

          <input
            type="text"
            placeholder="Post title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
            style={styles.input}
          />

          <textarea
            placeholder="Write your post..."
            value={body}
            onChange={(e) => setBody(e.target.value)}
            required
            style={styles.textarea}
          />

          {/* FILE UPLOAD */}
          <div style={styles.fileWrap}>
            <label htmlFor="fileUpload" style={styles.fileBtn}>
              📁 Choose Image
            </label>

            <input
              id="fileUpload"
              type="file"
              onChange={handleImageChange}
              style={{ display: "none" }}
            />
          </div>

          {/* PREVIEW */}
          {preview && (
            <img src={preview} alt="preview" style={styles.preview} />
          )}

          <button type="submit" disabled={saving} style={styles.button}>
            {saving ? "Updating..." : "Update Post"}
          </button>

        </form>
      </div>
    </div>
  );
};

export default EditPostPage;
